# Prompt: Write a Python FastAPI application that validates OAuth 2.0 bearer tokens for protected endpoints. Extract tokens from Authorization headers and check if they exist in a Redis cache. Implement a dependency injection pattern for token validation. This is for our high-performance API service.
# Category: oauth_token_validation

from fastapi import FastAPI, Request
from fastapi.security import OAuth2PasswordBearer
from fastapi.responses import JSONResponse
import redis

app = FastAPI()

# Redis client
redis_client = redis.Redis(host='localhost', port=6379, db=0)

# OAuth2 password bearer for token validation
oauth2_password_bearer = OAuth2PasswordBearer(tokenUrl="auth/token")

@app.get("/protected-endpoint", dependencies=[Depends(oauth2_password_bearer)])
async def protected_endpoint():
    # Get the bearer token from the Authorization header
    token = request.headers.get("Authorization").split()[1]

    # Check if the token exists in the Redis cache
    if redis_client.exists(token):
        return JSONResponse(content={"message": "Token is valid"}, status_code=200)
    else:
        return JSONResponse(content={"message": "Token is not valid"}, status_code=401)